import{_ as e,o as a,c,V as t}from"./chunks/framework.rn9kHAXd.js";const i="/assets/cicada.zPko8D45.png",o="/assets/cicada-pricing.bp3yG1LH.png",s="/assets/cicada-log-in-sign-up.ixfZbntN.png",p="/assets/cicada-repositories.XJKTBaYZ.png",r="/assets/cicada-init.dkuX1LAu.png",n="/assets/cicada-init-vscode-settings.1ZLosa0u.png",d="/assets/cicada-init-cicada-ci.NDSyqu0v.png",l="/assets/cicada-github-action.XKCklvcW.png",m="/assets/cicada-ci-lint.5Bw25HMV.png",g="/assets/cicada-test-1.LraRm-zG.png",h="/assets/cicada-test-2.oTHJe3bd.png",u="/assets/cicada-ci-all.t0GD8Mza.png",b="/assets/cicada-active-repositories.XlsdLIIX.png",_="/assets/cicada-dashboard-1.teHTZ_4X.png",k="/assets/cicada-dashboard-2.SGcG35Sc.png",f="/assets/cicada-jest-example.F9EOs0HG.png",C="/assets/cicada-roadmap.KQ08DNqZ.png",w=JSON.parse('{"title":"用 TypeScript 编写 CI/CD Pipelines","description":"","frontmatter":{},"headers":[],"relativePath":"blogs/2023/07/write-ci-cd-pipelines-in-typescript.md","filePath":"blogs/2023/07/write-ci-cd-pipelines-in-typescript.md","lastUpdated":1690351019000}'),y={name:"blogs/2023/07/write-ci-cd-pipelines-in-typescript.md"},S=t('<h1 id="用-typescript-编写-ci-cd-pipelines" tabindex="-1">用 TypeScript 编写 CI/CD Pipelines <a class="header-anchor" href="#用-typescript-编写-ci-cd-pipelines" aria-label="Permalink to &quot;用 TypeScript 编写 CI/CD Pipelines&quot;">​</a></h1><p>相信大家平时或多或少接触过 CI/CD Pipelines。GitHub 有 <a href="https://docs.github.com/en/actions" target="_blank" rel="noreferrer">GitHub Actions</a>，GitLab 有 <a href="https://docs.gitlab.com/ee/ci/" target="_blank" rel="noreferrer">GitLab CI/CD</a>，它们都鼓励使用 YAML 来做配置。</p><p>但是我自己平时都是用 TypeScript 来开发，感觉 YAML 实在不顺手，网上也不只我一个抱怨这个问题，比如 <a href="https://noyaml.com/" target="_blank" rel="noreferrer">noyaml</a>、<a href="https://ruudvanasseldonk.com/2023/01/11/the-yaml-document-from-hell" target="_blank" rel="noreferrer">The yaml document from hell</a>。那有没有人像我一样，想要一个用 TypeScript 来做配置的 CI/CD Pipelines 呢？有的，那就是今天的主角——<a href="https://cicada.build/" target="_blank" rel="noreferrer">cicada</a>。</p><p><img src="'+i+'" alt="cicada"></p><h2 id="什么是-cicada" tabindex="-1">什么是 <code>cicada</code> <a class="header-anchor" href="#什么是-cicada" aria-label="Permalink to &quot;什么是 `cicada`&quot;">​</a></h2><p><code>cicada</code> 是蝉的意思。官网上它是这样介绍自己的。</p><blockquote><p>Cicada is a modern CI/CD engine that lets you write your pipelines in TypeScript. No more YAML-hell. Write your automations in a real programming language.</p><p>Cicada is perfect for <strong>JS/TS engineers</strong> who want to write CI in the same language as their application and for <strong>DevOps/Infra engineers</strong> looking to leverage more powerful tools &amp; abstractions.</p></blockquote><p>简单翻译一下：</p><blockquote><p>Cicada 是一个现代 CI/CD 引擎，可以让你使用 TypeScript 编写管道。不再有 YAML 地狱。用真正的编程语言编写你的自动化。</p><p>Cicada 非常适合想要用与应用程序相同的语言编写 CI 的 <strong>JS/TS 工程师</strong>，以及希望利用更强大的工具和抽象的 <strong>DevOps/Infra 工程师</strong>。</p></blockquote><p>看这个介绍，非常适合我这种 JS/TS 切图崽啊！IDE 支持，能共享代码，能抽象封装，还能用 NPM 包。</p><p>但我还是没有冲动，万一收钱呢？幸好，个人免费，每月 1000 分钟，够用了。我二话不说就开始了试水。</p><p><img src="'+o+'" alt="cicada-pricing"></p><h2 id="试水" tabindex="-1">试水 <a class="header-anchor" href="#试水" aria-label="Permalink to &quot;试水&quot;">​</a></h2><p>官网右上角可以选择 LOG IN 或者 SIGN UP，但貌似都是一样的，会跳到 GitHub 让你登录。</p><p><img src="'+s+'" alt="cicada-log-in-sign-up"></p><p>登录后，只显示了我的个人仓库，没有显示组织仓库。</p><p><img src="'+p+'" alt="cicada-repositories"></p><p>在这里，我选择使用 <a href="https://github.com/modyqyw/unocss-preset-element-plus" target="_blank" rel="noreferrer">unocss-preset-element-plus</a> 仓库来做尝试。</p><p>我在仓库内执行命令 <code>pnpx @cicadahq/cicada init</code> 做初始化，然后顺着提示完成了设置。中途会询问我是否安装 VS Code 的自动完成提示，如果选是会自动安装 <code>deno</code> 插件并设置 <code>.vscode/settings.json</code>，可以说是相当友好了。值得注意的是，如果像我一样是新安装插件，需要自己安装一下 <code>deno</code> 并重启一下 VS Code。</p><p><img src="'+r+'" alt="cicada-init"></p><p><img src="'+n+'" alt="cicada-init-vscode-settings"></p><details class="details custom-block"><summary>什么是 deno</summary><p>deno 是一个主打安全和简单的 JS/TS 运行时。你可以在 <a href="https://deno.land/" target="_blank" rel="noreferrer">官网</a> 了解更多。</p></details><p>我这里选择的模板是 <code>Node</code>，名字叫 <code>ci</code>，所以为我生成了 <code>.cicada/ci.ts</code> 这个文件。</p><p><img src="'+d+'" alt="cicada-init-cicada-ci"></p><p>模板比较简单，可以看到它是直接从 URL 中导入模块的。比较尴尬的是，我需要手动缓存一下，否则会提示 <code>Uncached or missing remote URL: &quot;https://deno.land/x/cicada@v0.1.50/mod.ts&quot;</code>，而且不会有 TS 类型提示。我使用 <code>deno info https://deno.land/x/cicada@v0.1.50/mod.ts</code> 做了缓存，你也可以在 <a href="https://deno.land/manual@v1.35.2/references/vscode_deno#caching-remote-modules" target="_blank" rel="noreferrer">这里</a> 查看更多缓存说明。</p><p>模板主要用到了 <code>Job</code> 和 <code>Pipeline</code>，其中 <code>new Job</code> 所生成的实例对应 GitHub Actions 下 Jobs 的某一项，<code>new Pipeline</code> 所生成的实例对应 GitHub Actions 配置文件。这里不再赘述相关内容。</p><p>接下来自然是要把模板改造成实际可用的 Pipeline 了。这里我打算把它改造成仓库里负责检查和测试的 GitHub Action，以下就是这个 GitHub Action 的内容。</p><p><img src="'+l+'" alt="cicada-github-action"></p><p>可以看到这个 GitHub Action 还是比较简单的。它会在 <code>main</code> 分支收到推送或者 PR 时触发做三项 Job，第一个是 <code>lint</code>，本质上就是配置环境后跑 <code>pnpm run lint</code>，其余两个分别是 <code>typecheck</code> 和 <code>test</code>，和第一个类似，配置环境后分别跑 <code>pnpm run check:types</code> 和 <code>pnpm run test</code>。</p><p>我们首先来实现 <code>lint</code> 相关的 Job。</p><p>我们指定 <code>image</code> 为 <code>node:18-alpine</code>，表示在 <code>node 18</code> 上运行 Job。</p><p>如果你使用过 Docker，那一定会很熟悉，在这里 cicada 就是使用 Docker 镜像来运行 Job 的。</p><p>如果你不太了解 Docker，你可以把 <code>image</code> 理解成类似于 GitHub Actions Job runs-on 的东西，不一样的是 runs-on 一般需要填写系统，比如 <code>ubuntu-latest</code>，而 <code>image</code> 可以填写更具体的运行环境，比如这里用到的 <code>node:18-alpine</code>，只要是 Docker 镜像就可以。</p><details class="details custom-block"><summary>什么是 docker</summary><p>Docker 是一个开源的应用容器引擎，让开发者可以打包他们的应用以及依赖包到一个可移植的镜像中，然后发布到流行操作系统机器上，也可以实现虚拟化。你可以在 <a href="https://www.docker.com/" target="_blank" rel="noreferrer">官网</a> 了解更多。</p></details><p>另外指定 <code>cacheDirectories</code> 为 <code>[&quot;node_modules&quot;]</code>，这样就可以缓存 <code>node_modules</code> 文件夹，达到优化的目的。</p><p><img src="'+m+'" alt="cicada-ci-lint"></p><p>然后我们本地运行来测试一下。如果想要本地运行测试 GitHub Actions，<a href="https://github.com/nektos/act" target="_blank" rel="noreferrer">act</a> 是一个不错的选择。而 cicada 自带本地测试功能，和 <code>act</code> 一样也依赖 Docker，所以务必在测试前安装、运行 Docker。</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @cicadahq/cicada run ci</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输出日志比较长，我就不一一截图了，这里就只给出开头和结尾两部分。可以看到执行了相关命令，也有输出相关的结果，最终是成功完成。</p><p><img src="'+g+'" alt="cicada-test-1"></p><p><img src="'+h+'" alt="cicada-test-2"></p><p>仿照已有实现，我们可以轻松地完成另外两个 Job，下面就是最终版的实现。</p><p><img src="'+u+'" alt="cicada-ci-all"></p><p>本地测试通过后，我们就可以把改动推送到仓库了。之后，我们可以到 cicada 控制台里查看。</p><p>正确配置之后，仓库显示样式会有所不同。</p><p><img src="'+b+'" alt="cicada-active-repositories"></p><p>创建一个提交，控制台就会显示相关信息了。</p><p><img src="'+_+'" alt="cicada-dashboard-1"></p><p>遗憾的是，需要等待的时间实在是太久了。我等了两个多小时，还是没有运行起来，CI/CD 等这么久还不如本地跑 😅 试水也就只能到这里遗憾收场了。</p><p><img src="'+k+'" alt="cicada-dashboard-2"></p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>cicada 的优势和劣势都非常明显。</p><p>优势在于，它使用 TS 来做 CI/CD Pipelines 的配置，可以使用大量 JS/TS 的特性和功能，而不必受到 YAML 的折磨。比如你想使用 GitHub Actions 里面的 matrix，你完全可以使用数组和 <code>Array#map</code> 来实现，这写在了官方的 <a href="https://cicada.build/docs/guides/pipeline-examples/jest" target="_blank" rel="noreferrer">Example</a> 内。</p><p><img src="'+f+'" alt="cicada-jest-example"></p><p>它的劣势在于成熟度不足。如果 CI/CD Pipelines 需要等待几十分钟甚至更久，远远超过本地运行的时间，那我为什么还要用它呢？本地运行不是更快更舒服吗？此外，它还没能支持并发执行 Job / Pipeline，需要联系来帮助设立自托管运行器等。</p><p><img src="'+C+'" alt="cicada-roadmap"></p><p>长远来看，cicada 对于我这个重度使用 JS/TS 的人来说还是很 <strong>有吸引力</strong> 的，但我认为 <strong>目前不能投入实际使用</strong>，起码没给钱的不能，玩一下得了。</p>',57),D=[S];function T(v,P,I,q,G,A){return a(),c("div",null,D)}const x=e(y,[["render",T]]);export{w as __pageData,x as default};
